// src/App.js
import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import AppRoutes from "./routes/AppRoutes";

// Auth Pages
import Login from "./pages/auth/Login";
import Register from "./pages/auth/Register";

function App() {
  const userRole = localStorage.getItem("role");

  return (
    <Router>
      <Routes>
        {/* Default route: redirect logged-in users to their dashboard */}
        <Route
          path="/"
          element={
            userRole ? <Navigate to={`/${userRole}`} replace /> : <Login />
          }
        />

        {/* Optional Register Route */}
        <Route path="/register" element={<Register />} />

        {/* All other protected/dashboard routes */}
        <Route path="/*" element={<AppRoutes />} />

        {/* Fallback 404 page */}
        <Route
          path="*"
          element={
            <div
              style={{
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                height: "80vh",
                textAlign: "center",
                flexDirection: "column",
                padding: "20px",
              }}
            >
              <h1 style={{ fontSize: "2.5rem", color: "#ef4444", marginBottom: "15px" }}>
                404 Not Found
              </h1>
              <p style={{ color: "#374151", fontSize: "1.1rem" }}>
                The page you are looking for does not exist.
              </p>
              <a
                href="/"
                style={{
                  marginTop: "15px",
                  color: "#a71010",
                  fontWeight: "600",
                  textDecoration: "underline",
                  cursor: "pointer",
                }}
              >
                Go Back Home
              </a>
            </div>
          }
        />
      </Routes>
    </Router>
  );
}

export default App;
